     * @return the extracted metric value as a string, or null if not found
     * @throws IllegalArgumentException if input parameters are invalid
     * @throws RuntimeException         if XML parsing or XPath evaluation fails
     */
    public String extractMetric(String xmlContent, String xpathExpression) {
        // Validate input parameters
        if (xmlContent == null || xmlContent.trim().isEmpty()) {
            throw new IllegalArgumentException("XML content cannot be null or empty");
        }

        if (xpathExpression == null || xpathExpression.trim().isEmpty()) {
            throw new IllegalArgumentException("XPath expression cannot be null or empty");
        }

        try {
            // Create a secure DocumentBuilderFactory
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();

            // Security: Disable external entity processing to prevent XXE attacks
            factory.setFeature(XMLConstants.FEATURE_SECURE_PROCESSING, true);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            // Parse the XML content
            DocumentBuilder builder = factory.newDocumentBuilder();
            InputSource inputSource = new InputSource(new StringReader(xmlContent));
            org.w3c.dom.Document document = builder.parse(inputSource);

            // Create XPath instance
            XPathFactory xpathFactory = XPathFactory.newInstance();
            XPath xpath = xpathFactory.newXPath();

            // Compile and evaluate the XPath expression
            XPathExpression expression = xpath.compile(xpathExpression);
            String result = (String) expression.evaluate(document, XPathConstants.STRING);

            // Return the result, or null if empty
            return (result != null && !result.isEmpty()) ? result : null;

        } catch (javax.xml.parsers.ParserConfigurationException e) {
            throw new RuntimeException("Failed to configure XML parser: " + e.getMessage(), e);
        } catch (org.xml.sax.SAXException e) {
            throw new RuntimeException("Failed to parse XML content: " + e.getMessage(), e);
        } catch (java.io.IOException e) {
            throw new RuntimeException("Failed to read XML content: " + e.getMessage(), e);
        } catch (javax.xml.xpath.XPathExpressionException e) {
            throw new RuntimeException("Invalid XPath expression: " + e.getMessage(), e);
        } catch (Exception e) {
            throw new RuntimeException("Unexpected error during metric extraction: " + e.getMessage(), e);
        }
    }
}
